kernel_src="""

#include "kernel_operator.h"

constexpr int32_t BUFFER_NUM = 2;
constexpr float NEG_INF = -1.0e38f;

class KernelLogSoftmaxCustom {
public:
    __aicore__ inline KernelLogSoftmaxCustom() {}

    __aicore__ inline void Init(GM_ADDR x, GM_ADDR y,
                                uint32_t totalLength, uint32_t tileLength,
                                uint32_t blockDim, uint32_t dim)
    {
        totalLen_ = totalLength;
        tileLen_ = tileLength;
        blockDim_ = blockDim;
        dim_ = dim;
        batchSize_ = (dim_ == 0) ? 1 : (totalLen_ / dim_);

        xGm_.SetGlobalBuffer((__gm__ float*)x, totalLen_);
        yGm_.SetGlobalBuffer((__gm__ float*)y, totalLen_);

        pipe_.InitBuffer(inQueueX_, BUFFER_NUM, tileLen_ * sizeof(float));
        pipe_.InitBuffer(outQueueY_, BUFFER_NUM, tileLen_ * sizeof(float));
        // two temporary buffers for exp and sub
        pipe_.InitBuffer(tmpQueue1_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(tmpQueue2_, 1, tileLen_ * sizeof(float));
        pipe_.InitBuffer(scalarQueue_, 1, sizeof(float));
    }

    __aicore__ inline void Process()
    {
        if (totalLen_ == 0 || tileLen_ == 0 || batchSize_ == 0) return;

        const uint32_t blockIdx = static_cast<uint32_t>(AscendC::GetBlockIdx());

        for (uint32_t row = blockIdx; row < batchSize_; row += blockDim_) {
            uint32_t rowStart = row * dim_;

            // Pass 1: row max
            float maxVal = NEG_INF;
            uint32_t remaining = dim_;
            uint32_t offset = 0;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                LoadTile(rowStart + offset, curLen);
                AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
                for (uint32_t i = 0; i < curLen; i++) {
                    float val = xLocal.GetValue(i);
                    if (val > maxVal) maxVal = val;
                }
                inQueueX_.FreeTensor(xLocal);
                remaining -= curLen;
                offset += curLen;
            }

            // Pass 2: sum of exp(x - maxVal)
            float sum = 0.0f;
            remaining = dim_;
            offset = 0;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                LoadTile(rowStart + offset, curLen);
                AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();

                // tmp2 = x - maxVal  (using Adds with negative scalar)
                AscendC::LocalTensor<float> tmp2 = tmpQueue2_.AllocTensor<float>();
                AscendC::Adds(tmp2, xLocal, -maxVal, curLen);

                // tmp1 = exp(tmp2)
                AscendC::LocalTensor<float> tmp1 = tmpQueue1_.AllocTensor<float>();
                AscendC::Exp(tmp1, tmp2, curLen);

                // free tmp2 now
                tmpQueue2_.FreeTensor(tmp2);

                // scalar loop for sum
                for (uint32_t i = 0; i < curLen; i++) {
                    sum += tmp1.GetValue(i);
                }
                tmpQueue1_.FreeTensor(tmp1);
                inQueueX_.FreeTensor(xLocal);
                remaining -= curLen;
                offset += curLen;
            }

            // log(sum)
            AscendC::LocalTensor<float> logTensor = scalarQueue_.AllocTensor<float>();
            logTensor.SetValue(0, sum);
            AscendC::Log(logTensor, logTensor, 1);
            float logSum = logTensor.GetValue(0);
            scalarQueue_.FreeTensor(logTensor);

            float offsetVal = maxVal + logSum;

            // Pass 3: y = x - offsetVal  (using Adds with negative scalar)
            remaining = dim_;
            offset = 0;
            while (remaining > 0) {
                uint32_t curLen = (remaining > tileLen_) ? tileLen_ : remaining;
                LoadTile(rowStart + offset, curLen);
                AscendC::LocalTensor<float> xLocal = inQueueX_.DeQue<float>();
                AscendC::LocalTensor<float> yLocal = outQueueY_.AllocTensor<float>();
                AscendC::Adds(yLocal, xLocal, -offsetVal, curLen);
                inQueueX_.FreeTensor(xLocal);
                outQueueY_.EnQue<float>(yLocal);
                StoreTile(rowStart + offset, curLen);
                remaining -= curLen;
                offset += curLen;
            }
        }
    }

private:
    __aicore__ inline void LoadTile(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> xLocal = inQueueX_.AllocTensor<float>();
        AscendC::DataCopy(xLocal, xGm_[gmOffset], len);
        inQueueX_.EnQue(xLocal);
    }

    __aicore__ inline void StoreTile(uint32_t gmOffset, uint32_t len)
    {
        AscendC::LocalTensor<float> yLocal = outQueueY_.DeQue<float>();
        AscendC::DataCopy(yGm_[gmOffset], yLocal, len);
        outQueueY_.FreeTensor(yLocal);
    }

private:
    AscendC::TPipe pipe_;
    AscendC::TQue<AscendC::TPosition::VECIN, BUFFER_NUM> inQueueX_;
    AscendC::TQue<AscendC::TPosition::VECOUT, BUFFER_NUM> outQueueY_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue1_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> tmpQueue2_;
    AscendC::TQue<AscendC::TPosition::VECCALC, 1> scalarQueue_;

    AscendC::GlobalTensor<float> xGm_;
    AscendC::GlobalTensor<float> yGm_;

    uint32_t totalLen_ {0};
    uint32_t tileLen_ {0};
    uint32_t blockDim_ {0};
    uint32_t dim_ {0};
    uint32_t batchSize_ {0};
};

extern "C" __global__ __aicore__ void log_softmax_custom(GM_ADDR x, GM_ADDR y, GM_ADDR workspace, GM_ADDR tiling)
{
    GET_TILING_DATA(tiling_data, tiling);
    KernelLogSoftmaxCustom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength, tiling_data.blockDim, tiling_data.dim);
    op.Process();
}
